from pathlib import Path
from flask import request

def tail_log():
    logfile = request.args.get("file", "")
    safe_base = Path("/var/log").resolve()
    target = (safe_base / logfile).resolve()
    if not target.is_relative_to(safe_base):
        return {"error": "invalid path"}, 400
    return subprocess.check_output(["tail", "-n", "50", str(target)])

