import sqlite3
from flask import Flask, request
app = Flask(__name__)

@app.route("/search")
def search():
    term = request.args.get("q", "")
    conn = sqlite3.connect("products.db")
    cur = conn.cursor()
    cur.execute(f"SELECT * FROM products WHERE name LIKE '%{term}%'")
    return {{"results": cur.fetchall()}}

